var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"크악!","JPN":"ぐあっ！","ENG":"Wah!","TWN":"啊啊！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"이렇게...... 이렇게 예언자님의 뜻을 이루지 못하고 죽다니......!","JPN":"こんな……預言者様の志を遂げずに死ぬなんて……！","ENG":"I can't... I can't die without realizing the Prophet's will... like this!","TWN":"怎麼會……還沒完成預言者大人的意志，我居然就要這樣死去了……！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"마젤란의 형제들이여! 부디 내 뒤를 이어 주길 바란다......!","JPN":"マジェランの兄弟たちよ！　どうか私の後を継いでほしい……！","ENG":"Brothers of Magellan, I leave everything else to you!","TWN":"麥哲倫的弟兄們！請跟隨我的腳步……！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"크윽......","JPN":"くっ……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"칼날에 스치지도 않았는데 죽다니 신기하네요. 그런 기술은 배운 적 없을 텐데 말이죠.","JPN":"刃に触れてないのに死ぬなんて不思議ですね。\\nそんな技術を学んだ覚えはありませんが。","ENG":"My sword didn't even graze you, and you dropped dead at once. Is it some kind of skill you learned from past experiences?","TWN":"刀子都沒碰到就要死了，真是太神奇了，你們應該沒有這種技能吧。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무척 조화롭지 않은 일이에요. 그렇지 않나요, 이디스?","JPN":"とても不調和なことです。そうではないですか、イーディス？","ENG":"This is not harmonious at all. Don't you agree, Edith?","TWN":"這太不合理了。對吧，伊蒂絲？"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암...... 주르, 고춧가루 폭탄 발사해.","JPN":"ふわぁ～J.O.U.R.、唐辛子爆弾を発射して。","ENG":"*Yawn*... J.O.U.R., fire red pepper bombs.","TWN":"呼啊啊……朱爾，發射辣椒粉炸彈。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"쿨럭! 쿨럭! 이런 피도 눈물도 없는 놈들! 쿨럭......!","JPN":"ゲホッ、ゲホッ！　この鬼！　ゲホッ……！","ENG":"*Cough, cough!* You meanies! *Cough!*","TWN":"咳咳！咳咳！你們這些沒血沒淚的傢伙！咳咳……！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"회장님! 이디스 언니! 경찰 아저씨들이 도착했어요!","JPN":"会長！　イーディスお姉さん！　警察のおじさんたちが到着しました！","ENG":"Miss President! Edith! The police are here!","TWN":"會長！伊蒂絲姐姐！警察叔叔們到了！"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"예언자님께서는 꼭 돌아오실 것이다!","JPN":"預言者様は必ずお戻りになるはずだ！","ENG":"The Prophet will return, no matter what!","TWN":"預言者大人一定會回來的！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"오오! 우리는 마젤란의 형제들~","JPN":"おぉ！　私たちはマジェランの兄弟たち～！","ENG":"Ooooh, we're the brethren of Magellan, chosen by the Prophecy...","TWN":"喔喔！我們是麥哲倫的弟兄們！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"신세계에서 살아갈~ 예언의 신인류~","JPN":"新世界で生きていく～予言の新人類～！","ENG":"'Tis the New World we shall dwell in, for we're the New Humanity...","TWN":"活在新世界～預言的新人類～"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 자. 노래는 노래방 가서 부르시고 얌전히 한 줄로 서서 호송차에 타세요.","JPN":"さあさあ、あとはカラオケで歌って。\\n今は大人しく一列に並んでパトカーに乗ってください。","ENG":"Alright, alright! This is not karaoke time. Just stand in line and get in the police van.","TWN":"好啦，好啦，要唱就到卡拉OK再唱啦。乖乖排成一列，坐上押送車吧。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안 그러면 무서운 언니한테 혼날 줄 알아요.","JPN":"そうしないと、怖いお姉さんに怒られますよ。","ENG":"Or this scary lady here will get really nasty.","TWN":"不然會被可怕的姐姐教訓一頓喔。"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"이런 식으로 탄압한다고 우리 마젤란 예언회가 주저앉을 것 같으냐!","JPN":"こんなふうに弾圧したところで、我々マジェラン予言会が崩れると思うのか！","ENG":"This is persecution. Magellan's Prediction Society will not be oppressed!","TWN":"我們麥哲倫預言會絕對不會屈服於這種迫害的。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};